const BRANCHING = 32;               // must be a power of two
const SHIFT = 5;                    // log2(BRANCHING)
type Node<T> = { children: (Node<T> | T)[] };

function newNode<T>(children: (Node<T> | T)[]): Node<T> {
    return { children };
}

/**
 * Create a path of empty nodes down to the given leaf.
 */
function newPath<T>(level: number, node: Node<T>): Node<T> {
    let cur = node;
    for (let i = level; i > 0; i -= SHIFT) {
        cur = newNode<T>([cur]);
    }
    return cur;
}

/**
 * Insert a leaf (the old tail) into the tree.
 */
function pushTail<T>(root: Node<T> | null, depth: number, tailNode: Node<T>): Node<T> {
    if (root === null) {
        // tree was empty – the new root is just a path to the leaf
        return newPath<T>(depth, tailNode);
    }

    // descend recursively copying nodes on the path
    const newRoot = { children: root.children.slice() };
    let node: Node<T> = newRoot;
    for (let level = depth; level > SHIFT; level -= SHIFT) {
        const idx = ((node.children.length - 1) >>> level) & (BRANCHING - 1);
        const child = node.children[idx] as Node<T>;
        const newChild = { children: (child ? child.children.slice() : []) };
        node.children[idx] = newChild;
        node = newChild;
    }

    // now we are at the level just above leaves
    const leafIdx = ((node.children.length) >>> SHIFT) & (BRANCHING - 1);
    node.children[leafIdx] = tailNode;
    return newRoot;
}

/**
 * Retrieve the leaf node that contains element at `index`.
 */
function arrayFor<T>(root: Node<T> | null, depth: number, index: number, tail: T[]): (Node<T> | T[]) {
    if (index >= 0 && index < tail.length) return tail;
    if (!root) throw new Error('Index out of bounds');

    let node: Node<T> = root;
    for (let level = depth; level > 0; level -= SHIFT) {
        const idx = (index >>> level) & (BRANCHING - 1);
        node = node.children[idx] as Node<T>;
    }
    return node.children as T[];
}

