/** Parse a URL query string literal into an object type.
 *  Example:
 *    type T = ParseQuery<"a=1&b=2">; // => { a: "1"; b: "2" }
 */
export type ParseQuery<S extends string> = S extends ''
  ? {}
  : _ParseRec<S>;

type _ParseRec<
  Str extends string,
  Acc extends object = {}
> = Str extends `${infer Pair}&${infer Rest}`
  ? _ParseRec<Rest, _Merge<Acc, _PairToObj<Pair>>>
  : _Merge<Acc, _PairToObj<Str>>;

/** Convert a single `key=value` fragment into an object `{ key: value }`. */
type _PairToObj<P extends string> = P extends `${infer K}=${infer V}`
  ? { [k in K]: V }
  : {}; // ignore malformed fragments

/** Merge two object types (intersection works for distinct keys). */
type _Merge<A, B> = A & B;

// EventEmitter.ts
export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  // Store handlers per event name. The type is a partial mapped type so that
  // each key K holds an array of handlers whose signature matches TEvents[K].
  private listeners: Partial<{
    [K in keyof TEvents]: Array<(...args: TEvents[K]) => void>;
  }> = {};

  /**
   * Register a handler for the given event name.
   *
   * The compiler enforces that `name` is a key of TEvents and that the
   * handler's parameters exactly match the tuple type associated with that key.
   */
  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    // Initialise the array if it does not exist yet, then push the handler.
    const arr = (this.listeners[name] ??= []);
    arr.push(handler);
  }

  /**
   * Emit an event, invoking all registered handlers in the order they were added.
   *
   * The compiler checks that `name` is a valid event key and that the supplied
   * arguments conform to the tuple type defined for that event.
   */
  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this.listeners[name];
    if (!handlers) return; // no listeners for this event

    // Call each handler with the provided arguments.
    for (const h of handlers) {
      h(...args);
    }
  }
}

